#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int data;
    struct Node *left, *right;
} Node;

Node* newNode(int val) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->data = val; n->left = n->right = NULL; return n;
}

// Helper to build tree and fill preorder array
void build(int *in, int *post, int inL, int inR, int postL, int postR, int *posMap, int *pre, int *preIdx) {
    if (inL > inR || postL > postR) return;
    int rootVal = post[postR];
    pre[(*preIdx)++] = rootVal;
    int rootPos = posMap[rootVal]; // value is used as index directly (values are ≤ N)
    int leftSize = rootPos - inL;
    // left subtree
    build(in, post, inL, rootPos-1, postL, postL+leftSize-1, posMap, pre, preIdx);
    // right subtree
    build(in, post, rootPos+1, inR, postL+leftSize, postR-1, posMap, pre, preIdx);
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *in = (int*)malloc(N*sizeof(int));
        int *post = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &in[i]);
        for(int i=0;i<N;i++) scanf("%d", &post[i]);
        // map value -> index in inorder (values are ≤ N according to constraints, otherwise use hashmap)
        int *posMap = (int*)calloc(100001, sizeof(int)); // safe upper bound
        for(int i=0;i<N;i++) posMap[in[i]] = i;
        int *pre = (int*)malloc(N*sizeof(int));
        int preIdx = 0;
        build(in, post, 0, N-1, 0, N-1, posMap, pre, &preIdx);
        for(int i=0;i<N;i++){
            if(i) printf(" ");
            printf("%d", pre[i]);
        }
        printf("\n");
        free(in); free(post); free(posMap); free(pre);
    }
    return 0;
}

