#include <bits/stdc++.h>
using namespace std;

void build(const vector<int>& inorder, const vector<int>& postorder,
           int inL, int inR, int postL, int postR,
           const unordered_map<int,int>& idxMap,
           vector<int>& preorder){
    if(inL>inR || postL>postR) return;
    int root = postorder[postR];
    preorder.push_back(root);
    int pos = idxMap.at(root);
    int leftSize = pos - inL;
    build(inorder, postorder, inL, pos-1, postL, postL+leftSize-1, idxMap, preorder);
    build(inorder, postorder, pos+1, inR, postL+leftSize, postR-1, idxMap, preorder);
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> inorder(N), postorder(N);
        for(int &x: inorder) cin>>x;
        for(int &x: postorder) cin>>x;
        unordered_map<int,int> idxMap; idxMap.reserve(N*2);
        for(int i=0;i<N;i++) idxMap[inorder[i]] = i;
        vector<int> preorder; preorder.reserve(N);
        build(inorder, postorder, 0, N-1, 0, N-1, idxMap, preorder);
        for(int i=0;i<N;i++){
            if(i) cout << ' ';
            cout << preorder[i];
        }
        if(T) cout << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static void build(int[] inorder, int[] postorder, int inL, int inR, int postL, int postR,
                      Map<Integer,Integer> idxMap, List<Integer> preorder) {
        if(inL > inR || postL > postR) return;
        int root = postorder[postR];
        preorder.add(root);
        int pos = idxMap.get(root);
        int leftSize = pos - inL;
        build(inorder, postorder, inL, pos-1, postL, postL+leftSize-1, idxMap, preorder);
        build(inorder, postorder, pos+1, inR, postL+leftSize, postR-1, idxMap, preorder);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] inorder = new int[N];
            int[] postorder = new int[N];
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) inorder[i] = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) postorder[i] = Integer.parseInt(st.nextToken());
            Map<Integer,Integer> idxMap = new HashMap<>(N*2);
            for (int i = 0; i < N; i++) idxMap.put(inorder[i], i);
            List<Integer> preorder = new ArrayList<>(N);
            build(inorder, postorder, 0, N-1, 0, N-1, idxMap, preorder);
            for (int i = 0; i < N; i++) {
                if (i > 0) out.append(' ');
                out.append(preorder.get(i));
            }
            if (T > 0) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

